import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';

/**
 * Компонент кнопки Home для бічного меню, який перенаправляє користувача на основі його ролі
 */
function SidebarHome() {
  const navigate = useNavigate();
  const [destination, setDestination] = useState('/dashboard'); // За замовчуванням - звичайна панель

  useEffect(() => {
    // Перевіряємо роль користувача при ініціалізації
    const checkUserRole = async () => {
      const userId = localStorage.getItem('user_id');
      if (!userId) return;
      
      try {
        const response = await fetch(`http://localhost:5000/api/user-role/${userId}`);
        
        if (!response.ok) {
          throw new Error('Failed to verify user role');
        }
        
        const data = await response.json();
        
        if (data.role === 'admin') {
          setDestination('/admin-dashboard');
        } else {
          setDestination('/dashboard');
        }
      } catch (error) {
        console.error('Error checking user role:', error);
      }
    };
    
    checkUserRole();
  }, []);

  return (
    <button onClick={() => navigate(destination)}>
      Home
    </button>
  );
}

export default SidebarHome;
